.be-live-list-count {
  opacity: 0.5;
  font-size: 12px;
}
.be-live-list-actions {
  display: flex;
  align-items: center;
  gap: 4px;
}
.be-live-list-refresh {
  cursor: pointer;
  padding: 2px;
}
.be-live-list-refresh .be-icon {
  opacity: 0.5;
