  top: 50%;
  left: calc(100% + 8px);
  transform: scale(0.9) translateY(-50%);
  transform-origin: left;
  padding: 4px;
  max-height: calc(100vh - 150px);
  background-color: #fff;
  color: black;
  border-radius: 8px;
  border: 1px solid #8882;
  box-sizing: border-box;
  box-shadow: 0 4px 12px 0 rgba(0, 0, 0, 0.05);
  overflow: auto;
  scrollbar-width: none !important;
  overscroll-behavior: contain;
  border-radius: 4px;
}
body.dark .badge-popup {
  box-shadow: 0 4px 12px 0 rgba(0, 0, 0, 0.2);
}
body.dark .badge-popup {
  background-color: var(--be-color-card-bg, #282828);
  color: var(--be-color-text-title, #eee);
}
.badge-popup::-webkit-scrollbar {
  height: 0 !important;
  width: 0 !important;
}
.badge-popup.open {
  transform: scale(1) translateY(-50%);
}
body.settings-panel-dock-right .badge-popup {
  right: calc(100% + 8px);
  left: unset;
  transform-origin: right;
}
.badge-popup, .badge-popup * {
  transition: 0.2s ease-out;
}
.badge-popup ul {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  grid-template-columns: repeat(2, 1fr);
}
.badge-popup ul li {
  border-radius: 4px;
  cursor: pointer;
  padding: 6px 8px;
  display: flex;
  justify-content: center;
}
.badge-popup ul li:hover {
  background-color: #8882;
}
.badge-popup ul li.active {
  box-shadow: 0 0 0px 1px var(--theme-color), 0 0 0px 3px var(--theme-color-20);
}
.badge-popup ul li.gray:not(:hover) {
  filter: grayscale(1);
}
.badge-popup ul li .title-image {
  display: inline-block;
  vertical-align: middle;
  height: 20px;
}
.badge-popup ul li .fans-medal-item {
  display: flex !important;
  height: 14px;
  line-height: 14px;
  color: #fff;
  border: 1px solid #f6be18;
  background-color: #f6be18;
  border-left: 0;
  white-space: nowrap;
  border-radius: 2px;
  flex-shrink: 0;
  font-size: 12px;
}
.badge-popup ul li .fans-medal-item .label {
  width: 40px;
  text-align: center;
  padding: 0 2px;
  color: #fff;
  border-radius: 1px 0 0 1px;
  background-color: #f6be18;
}
.badge-popup ul li .fans-medal-item .level {
  width: 16px;
  background-color: #fff;
  text-align: center;
  color: #f6be18;
  border-radius: 0 1px 1px 0;
}
.badge-popup ul li .fans-medal-item .label,
.badge-popup ul li .fans-medal-item .level {
  cursor: pointer;
  position: relative;
  display: block;
  float: left;
}
